using System.Security.Cryptography;using System.Text;using Dapper;using IntegraRP.Infrastructure.Data;using Microsoft.Extensions.Logging;
namespace IntegraRP.Infrastructure.Data.Migrations;public sealed class PostgresMigrationRunner(IDbConnectionFactory factory,ILogger<PostgresMigrationRunner> logger):IMigrationRunner{const long LockKey=2026070201;public async Task RunAsync(CancellationToken ct){try{logger.LogInformation("Iniciando migrations IntegraRP");var root=FindRepoRoot();var dir=Path.Combine(root,"database","migrations");if(!Directory.Exists(dir)){logger.LogWarning("Diretório de migrations não encontrado: {Dir}",dir);return;}using var cn=await factory.OpenConnectionAsync(ct);await cn.ExecuteAsync("CREATE EXTENSION IF NOT EXISTS pgcrypto; CREATE SCHEMA IF NOT EXISTS integrarp; CREATE TABLE IF NOT EXISTS integrarp.schema_migrations(version text primary key, checksum text not null, executado_em timestamptz not null default now());");await cn.ExecuteAsync("SELECT pg_advisory_lock(@LockKey)",new{LockKey});try{foreach(var file in Directory.GetFiles(dir,"*.sql").OrderBy(x=>x)){var version=Path.GetFileName(file);var sql=await File.ReadAllTextAsync(file,ct);var checksum=Convert.ToHexString(SHA256.HashData(Encoding.UTF8.GetBytes(sql)));var existing=await cn.QuerySingleOrDefaultAsync<string>("SELECT checksum FROM integrarp.schema_migrations WHERE version=@version",new{version});if(existing==checksum){logger.LogInformation("Migration {Version} já aplicada",version);continue;}if(existing is not null)throw new InvalidOperationException($"Migration {version} já aplicada com checksum diferente.");using var tx=cn.BeginTransaction();try{await cn.ExecuteAsync(sql,transaction:tx);await cn.ExecuteAsync("INSERT INTO integrarp.schema_migrations(version,checksum) VALUES(@version,@checksum)",new{version,checksum},tx);tx.Commit();logger.LogInformation("Migration {Version} aplicada",version);}catch(Exception ex){tx.Rollback();logger.LogError(ex,"Erro aplicando migration {Version}",version);throw;}}}finally{await cn.ExecuteAsync("SELECT pg_advisory_unlock(@LockKey)",new{LockKey});}}catch(Exception ex){logger.LogError(ex,"Falha no migration runner IntegraRP");throw;}}
static string FindRepoRoot(){var d=new DirectoryInfo(AppContext.BaseDirectory);while(d is not null && !Directory.Exists(Path.Combine(d.FullName,"database")))d=d.Parent;return d?.FullName??Directory.GetCurrentDirectory();}}
